// Carbon calculation functions
const emissions = $fromAI('emissions_value', 'Emissions value in kg CO2e', 'number');
const energy = $fromAI('energy_kwh', 'Energy consumption in kWh', 'number', 0);
const operation = $fromAI('operation', 'Calculation type: footprint, intensity, efficiency, savings', 'string');

const CARBON_INTENSITY_GRID = 0.475; // kg CO2e per kWh (global average)
const RENEWABLE_INTENSITY = 0.05; // kg CO2e per kWh

let result;
if (operation === 'footprint') {
  result = energy * CARBON_INTENSITY_GRID;
} else if (operation === 'intensity') {
  result = emissions / Math.max(energy, 1);
} else if (operation === 'efficiency') {
  result = 100 - ((emissions / (energy * CARBON_INTENSITY_GRID)) * 100);
} else if (operation === 'savings') {
  result = energy * (CARBON_INTENSITY_GRID - RENEWABLE_INTENSITY);
} else {
  result = emissions;
}

return { result: result.toFixed(2), unit: 'kg CO2e', operation };

